{
    private readonly FormatProviderCollection _formatProviders;

    public MappingBuilderContext(
        SimpleMappingBuilderContext parentCtx,
        InstanceConstructorFactory instanceConstructors,
        FormatProviderCollection formatProviders,
        IUserMapping? userMapping,
        TypeMappingKey mappingKey,
        Location? diagnosticLocation = null,
        bool supportsDeepCloning = true
    )
        : base(parentCtx, diagnosticLocation ?? userMapping?.Method.GetSyntaxLocation())
    {
        InstanceConstructors = instanceConstructors;
        _formatProviders = formatProviders;
        UserMapping = userMapping;
        MappingKey = mappingKey;
        Configuration = ReadConfiguration(
            new MappingConfigurationReference(UserSymbol, mappingKey.Source, mappingKey.Target),
            supportsDeepCloning
        );
    }

    protected MappingBuilderContext(
        MappingBuilderContext ctx,
        IUserMapping? userMapping,
        Location? diagnosticLocation,
        TypeMappingKey mappingKey,
        bool ignoreDerivedTypes,
        bool supportsDeepCloning = true
    )
        : this(
            ctx,
            ctx.InstanceConstructors,
            ctx._formatProviders,
            userMapping,
            mappingKey,
            diagnosticLocation,
            supportsDeepCloning: supportsDeepCloning
        )
    {
        // Wrap parent scope in a child (delegates MarkUsed upward), or initialize from user mapping.
        // Only the root scope reports unused parameters in diagnostics.
        ParameterScope = ctx.ParameterScope.IsEmpty ? BuildParameterScope(userMapping) : new ParameterScope(ctx.ParameterScope);
        if (ignoreDerivedTypes)
        {
            Configuration = Configuration with { DerivedTypes = [] };
        }
    }

    private static ParameterScope BuildParameterScope(IUserMapping? userMapping) =>
        userMapping is IParameterizedMapping { AdditionalSourceParameters.Count: > 0 } pm
            ? new ParameterScope(pm.AdditionalSourceParameters)
            : ParameterScope.Empty;

    public TypeMappingKey MappingKey { get; }

    public ITypeSymbol Source => MappingKey.Source;

