   105	        MappingBuilderContext ctx,
   106	        IMapping mapping,
   107	        HashSet<string> valueConfiguredTargetPaths,
   108	        ListDictionary<string, IMemberPathConfiguration> configuredTargetMembersByRootName
   109	    )
   110	    {
   111	        // order by target path count as objects with less path depth should be mapped first
   112	        // to prevent NREs in the generated code
   113	        var result = new ListDictionary<string, MemberMappingConfiguration>();
   114	        foreach (var config in ctx.Configuration.Members.ExplicitMappings.OrderBy(cfg => cfg.Target.PathCount))
   115	        {
   116	            // if MapValue is already configured for this target member
   117	            // no additional MapProperty is allowed => diagnostic duplicate config.
   118	            if (valueConfiguredTargetPaths.Contains(config.Target.FullName))
   119	            {
   120	                ctx.ReportDiagnostic(
   121	                    DiagnosticDescriptors.MultipleConfigurationsForTargetMember,
   122	                    mapping.TargetType.ToDisplayString(),
   123	                    config.Target.FullName
   124	                );
   125	                continue;
   126	            }
   127	
   128	            configuredTargetMembersByRootName.Add(config.Target.RootName, config.Target);
   129	            result.Add(config.Target.RootName, config);
   130	        }
   131	
   132	        return result.AsDictionary();
   133	    }
   134	}

